// staleIndexDisagreement reports when childIndex and openChildIndex are
// inconsistent for b: an entry appears in openChildIndex but its Status is
// closed/cancelled, or an open child in childIndex is missing from the
// open-child bucket.
func staleIndexDisagreement(b Bead, childIndex, openChildIndex map[string][]Bead) string {
	open := openChildIndex[b.ID]
	all := childIndex[b.ID]
	for _, c := range open {
		if c.Status == StatusClosed || c.Status == StatusCancelled {
			return fmt.Sprintf("open-child index lists %s with closed status", c.ID)
		}
	}
	openIDs := map[string]bool{}
	for _, c := range open {
		openIDs[c.ID] = true
	}
	for _, c := range all {
		isOpenStatus := c.Status != StatusClosed && c.Status != StatusCancelled
		if isOpenStatus && !openIDs[c.ID] {
			return fmt.Sprintf("child %s has open status but missing from open-child index", c.ID)
		}
	}
	return ""
}

func isAutoRemediationExhausted(b Bead) bool {
	if extraStringVal(b.Extra, "auto-remediation-exhausted") == "true" {
		return true
	}
	for _, l := range b.Labels {
		if l == "auto-remediation:exhausted" {
			return true
		}
	}
	return false
}

	for _, key := range keys {
		if b.Extra != nil {
			if _, ok := b.Extra[key]; ok {
				return true
			}
		}
	}
	return false
}

func isExpiredRetryAfter(b Bead, now time.Time) bool {
	raw, ok := b.Extra[ExtraRetryAfter].(string)
	if !ok || raw == "" {
		return false
	}
	t, err := time.Parse(time.RFC3339, raw)
	return err == nil && !t.After(now)
}

func noChangesCount(b Bead) int {
	if b.Extra == nil {
		return 0
	}
	switch v := b.Extra[ExtraNoChangesCount].(type) {
	case int:
		return v
	case int64:
		return int(v)
	case float64:
		return int(v)
	}
	return 0
}

func isContainerBead(b Bead, childCount int) bool {
	if childCount == 0 {
		return false
	}
	return b.IssueType == "epic" || strings.HasPrefix(strings.ToLower(b.Title), "epic:")
}

func hasLabel(b Bead, label string) bool {
	for _, existing := range b.Labels {
		if existing == label {
			return true
		}
	}
	return false
}

func addLabel(b *Bead, label string) {
	for _, existing := range b.Labels {
		if existing == label {
			return
		}
	}
	b.Labels = append(b.Labels, label)
}

func removeLabel(b *Bead, label string) {
	out := b.Labels[:0]
	for _, existing := range b.Labels {
		if existing != label {
			out = append(out, existing)
		}
	}
	b.Labels = out
}

